// The fundamental shape
type IsString<T> = T extends string ? "yes" : "no";

type A = IsString<string>;   // "yes"
type B = IsString<number>;   // "no"
type C = IsString<"hello">;  // "yes" — string literal extends string

// Checking assignability, not equality
type IsArray<T> = T extends unknown[] ? true : false;
type D = IsArray<string[]>;  // true
type E = IsArray<readonly string[]>;  // false — readonly array ≠ mutable array
type F = IsArray<[string, number]>;   // true — tuple extends unknown[]

type ToArray<T> = T extends unknown ? T[] : never;

type StringArr = ToArray<string>;          // string[]
type StringOrNum = ToArray<string | number>; // string[] | number[]
// Distribution: (string extends unknown ? string[] : never)
//             | (number extends unknown ? number[] : never)
// = string[] | number[]

// Filtering a union — keep only string types
type OnlyStrings<T> = T extends string ? T : never;
type Mixed = string | number | boolean | null;
type JustStrings = OnlyStrings<Mixed>; // string

// Extracting array element type using distribution
type Flatten<T> = T extends (infer Item)[] ? Item : T;
type Nums = Flatten<number[]>;      // number
type Str  = Flatten<string>;        // string (not an array — pass-through)

// Extract the return type of any function
type ReturnType<T> = T extends (...args: unknown[]) => infer R ? R : never;

type R1 = ReturnType<() => string>;          // string
type R2 = ReturnType<(x: number) => boolean>; // boolean

// Extract a promise's resolved value
type Awaited<T> = T extends Promise<infer U> ? Awaited<U> : T;

type R3 = Awaited<Promise<string>>;              // string
type R4 = Awaited<Promise<Promise<number>>>;      // number (recursive)

// Extract parameter types as a tuple
type Parameters<T extends (...args: unknown[]) => unknown> =
  T extends (...args: infer P) => unknown ? P : never;

type P = Parameters<(a: string, b: number) => void>; // [string, number]

// Extract the first parameter only
type FirstParam<T> = T extends (first: infer F, ...rest: unknown[]) => unknown ? F : never;
type FP = FirstParam<(x: string, y: number) => void>; // string

// Real-world: infer the element type of any iterable
type ElementOf<T> = T extends Iterable<infer E> ? E : never;
type SE = ElementOf<Set<string>>;     // string
type ME = ElementOf<Map<string, number>>; // [string, number]

// Infer the value type in a Record
type ValueOf<T> = T extends Record<string, infer V> ? V : never;
type V = ValueOf<Record<string, User>>;  // User

// Infer the type of a signal's value (Angular)
import { Signal } from '@angular/core';
type SignalValue<T> = T extends Signal<infer V> ? V : never;
declare const count: Signal<number>;
type N = SignalValue<typeof count>; // number

// Distributive — checks each member separately
type IsString1<T> = T extends string ? true : false;
type D1 = IsString1<string | number>; // boolean (true | false)

// Non-distributive — compares the union as one type
type IsString2<T> = [T] extends [string] ? true : false;
type D2 = IsString2<string | number>; // false (union is not assignable to string)
type D3 = IsString2<string>;          // true

// IsNever — requires non-distributive form
// With distribution, never distributes to zero members → result is also never
type IsNever<T> = [T] extends [never] ? true : false;
type N1 = IsNever<never>;  // true
type N2 = IsNever<string>; // false

// Without the tuple trick:
type BrokenIsNever<T> = T extends never ? true : false;
type B1 = BrokenIsNever<never>;  // never  ← wrong!

// TypeName utility — maps a type to its name as a string literal
type TypeName<T> =
  T extends string  ? "string"  :
  T extends number  ? "number"  :
  T extends boolean ? "boolean" :
  T extends undefined ? "undefined" :
  T extends null    ? "null"    :
  T extends Function ? "function" :
  T extends unknown[] ? "array" :
  "object";

type TN1 = TypeName<string>;          // "string"
type TN2 = TypeName<number[]>;        // "array"
type TN3 = TypeName<{ a: number }>;   // "object"
type TN4 = TypeName<string | number>; // "string" | "number"  — distributed!

// Safer: use a function to narrow at runtime, using the type for checking
function getTypeName<T>(value: T): TypeName<T> {
  if (typeof value === 'string')   return 'string'  as TypeName<T>;
  if (typeof value === 'number')   return 'number'  as TypeName<T>;
  if (typeof value === 'boolean')  return 'boolean' as TypeName<T>;
  if (Array.isArray(value))        return 'array'   as TypeName<T>;
  if (value === null)              return 'null'    as TypeName<T>;
  if (value === undefined)         return 'undefined' as TypeName<T>;
  if (typeof value === 'function') return 'function' as TypeName<T>;
  return 'object' as TypeName<T>;
}

import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

// Extract the response body type from an observable
type ObservableValue<T> = T extends Observable<infer V> ? V : never;

// A generic API result wrapper
type ApiResult<T> = {
  data: T;
  status: 'success' | 'error';
  message: string;
};

// Service method with precise typing
class ApiService {
  constructor(private http: HttpClient) {}

  get<T>(url: string): Observable<ApiResult<T>> {
    return this.http.get<ApiResult<T>>(url);
  }
}

// The declared return type is statically checked:
// get<User>('/api/user') returns Observable<ApiResult<User>>
// NOT Observable<ApiResult<unknown>>

import { signal, computed, Signal } from '@angular/core';

// Utility: unwrap the value type from a signal
type SignalValue<S> = S extends Signal<infer V> ? V : never;

// Utility: make all signal fields into their value types (for template data)
type Unwrapped<T> = {
  [K in keyof T]: T[K] extends Signal<infer V> ? V : T[K];
};

// Example component state
interface State {
  count: Signal<number>;
  name: Signal<string>;
  loading: Signal<boolean>;
  label: string; // non-signal stays as-is
}

type FlatState = Unwrapped<State>;
// {
//   count: number;
//   name: string;
//   loading: boolean;
//   label: string;
// }

import { ActivatedRoute } from '@angular/router';

// Make specific route params required or optional based on route config
type RouteParams<T extends string> = { [K in T]: string };
type OptionalRouteParams<T extends string> = { [K in T]?: string };

// Conditional: required if in a list, optional otherwise
type RouteData<
  Required extends string,
  Optional extends string = never
> = RouteParams<Required> & OptionalRouteParams<Optional>;

// Usage:
type UserRoute = RouteData<'userId', 'tab'>;
// { userId: string; tab?: string }

// Deep flatten: string[][][] → string
type DeepFlatten<T> = T extends (infer Item)[]
  ? DeepFlatten<Item>
  : T;

type Flat1 = DeepFlatten<string[]>;      // string
type Flat2 = DeepFlatten<string[][]>;    // string
type Flat3 = DeepFlatten<string[][][]>;  // string

// Deep await: unwrap any depth of Promise
type DeepAwaited<T> = T extends Promise<infer U> ? DeepAwaited<U> : T;

type A1 = DeepAwaited<Promise<string>>;                   // string
type A2 = DeepAwaited<Promise<Promise<Promise<number>>>>;  // number

// Deep readonly — make all nested objects readonly
type DeepReadonly<T> = T extends object
  ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;

interface Config {
  server: { host: string; port: number };
  features: string[];
}

type ReadonlyConfig = DeepReadonly<Config>;
// { readonly server: { readonly host: string; readonly port: number }; readonly features: readonly string[] }

// Extract event name from 'on<Event>' handler name
type EventName<T extends string> = T extends `on${infer E}` ? E : never;

type E1 = EventName<'onClick'>;   // 'Click'
type E2 = EventName<'onChange'>;  // 'Change'
type E3 = EventName<'value'>;     // never — no 'on' prefix

// Lowercase the inferred part (TypeScript built-in string manipulation)
type EventNameLower<T extends string> = T extends `on${infer E}` ? Lowercase<E> : never;
type E4 = EventNameLower<'onClick'>; // 'click'

// Extract store action category: 'UserActions.Load' → 'UserActions'
type ActionCategory<T extends string> = T extends `${infer Cat}.${string}` ? Cat : never;
type C = ActionCategory<'UserActions.Load' | 'ProductActions.Fetch'>;
// 'UserActions' | 'ProductActions'

// Angular: typed route param extraction
// '/users/:id/posts/:postId' → 'id' | 'postId'
type ExtractParams<T extends string> =
  T extends `${string}:${infer Param}/${infer Rest}`
    ? Param | ExtractParams<`/${Rest}`>
    : T extends `${string}:${infer Param}`
      ? Param
      : never;

type Params = ExtractParams<'/users/:id/posts/:postId'>;
// 'id' | 'postId'

// Pitfall: accidentally producing never
type ExtractString<T> = T extends string ? T : never;
type R = ExtractString<number>; // never — expected
type R2 = ExtractString<never>; // never — also expected, but surprising

// Pitfall: forgetting that infer only works in extends position
// WRONG: infer outside conditional
// type Bad<T> = infer R;  // syntax error

// Pitfall: circular conditional type (TypeScript will error)
// type Circular<T> = T extends Circular<T> ? true : false; // Error

// Pitfall: overcomplicating — check if a simpler mapped type works first
// UNNECESSARY conditional:
type MakeOptional<T, K extends keyof T> = {
  [P in keyof T]: P extends K ? T[P] | undefined : T[P]
};
// SIMPLER with built-ins:
type MakeOptional2<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;

// infer in covariant position (function return, array element): union of possible types
type UnionInfer<T> = T extends { a: infer U; b: infer U } ? U : never;
type UI = UnionInfer<{ a: string; b: number }>; // string | number

// infer in contravariant position (function parameter): intersection of possible types
type IntersectionInfer<T> = T extends {
  fn: (x: infer U) => void;
  gn: (x: infer U) => void;
} ? U : never;
type II = IntersectionInfer<{
  fn: (x: string) => void;
  gn: (x: number) => void;
}>; // string & number  (= never for incompatible types)

// Pattern: use a type assertion helper that fails to compile if wrong
type Expect<T extends true> = T;
type Equal<A, B> = [A] extends [B] ? ([B] extends [A] ? true : false) : false;

// Tests — these compile only when the conditional types produce the correct result
type Tests = [
  Expect<Equal<ReturnType<() => string>, string>>,
  Expect<Equal<Awaited<Promise<number>>, number>>,
  Expect<Equal<Extract<string | number | boolean, string | number>, string | number>>,
  Expect<Equal<Exclude<string | number | boolean, boolean>, string | number>>,
  Expect<Equal<NonNullable<string | null | undefined>, string>>,
];
// If any type in Tests is false, the line produces a TS error — acts as a type test

// In a .spec.ts file (for documentation / regression prevention):
it('type: ReturnType extracts function return', () => {
  type Test = Expect<Equal<ReturnType<() => string>, string>>;
  const _typeTest: Test = true; // only compiles if Test = true
  expect(true).toBe(true);      // always passes at runtime
});
